      incisos: [{"id":"cf:art-3-inc-I","numero":"I","texto":"construir uma sociedade livre, justa e solidária;","alineas":[]},{"id":"cf:art-3-inc-II","numero":"II","texto":"garantir o desenvolvimento nacional;","alineas":[]},{"id":"cf:art-3-inc-III","numero":"III","texto":"erradicar a pobreza e a marginalização e reduzir as desigualdades sociais e regionais;","alineas":[]},{"id":"cf:art-3-inc-IV","numero":"IV","texto":"promover o bem de todos, sem preconceitos de origem, raça, sexo, cor, idade e quaisquer outras formas de discriminação.","alineas":[]}],
