      paragrafos: [{"id":"cf:art-4-púnico","numero":"único","texto":"A República Federativa do Brasil buscará a integração econômica, política, social e cultural dos povos da América Latina, visando à formação de uma comunidade latino-americana de nações.","alineas":[]}],
      incisos: [{"id":"cf:art-4-inc-I","numero":"I","texto":"independência nacional;","alineas":[]},{"id":"cf:art-4-inc-II","numero":"II","texto":"prevalência dos direitos humanos;","alineas":[]},{"id":"cf:art-4-inc-III","numero":"III","texto":"autodeterminação dos povos;","alineas":[]},{"id":"cf:art-4-inc-IV","numero":"IV","texto":"não-intervenção;","alineas":[]},{"id":"cf:art-4-inc-V","numero":"V","texto":"igualdade entre os Estados;","alineas":[]},{"id":"cf:art-4-inc-VI","numero":"VI","texto":"defesa da paz;","alineas":[]},{"id":"cf:art-4-inc-VII","numero":"VII","texto":"solução pacífica dos conflitos;","alineas":[]},{"id":"cf:art-4-inc-VIII","numero":"VIII","texto":"repúdio ao terrorismo e ao racismo;","alineas":[]},{"id":"cf:art-4-inc-IX","numero":"IX","texto":"cooperação entre os povos para o progresso da humanidade;","alineas":[]},{"id":"cf:art-4-inc-X","numero":"X","texto":"concessão de asilo político.","alineas":[]}],
