      paragrafos: [{"id":"cf:art-9-p1","numero":"1","texto":"A lei definirá os serviços ou atividades essenciais e disporá sobre o atendimento das necessidades inadiáveis da comunidade.","alineas":[]},{"id":"cf:art-9-p2","numero":"2","texto":"Os abusos cometidos sujeitam os responsáveis às penas da lei.","alineas":[]}],
