      caput: "Nas Varas do Trabalho, a jurisdição será exercida por um juiz singular.",
      paragrafos: [{"id":"cf:art-116-púnico","numero":"único","texto":"Os juízes classistas das Juntas de Conciliação e Julgamento serão nomeados pelo Presidente do Tribunal Regional do Trabalho, na forma da lei, permitida uma recondução.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"Nas Varas do Trabalho, a jurisdição será exercida por um juiz singular.","redacaoDadaPor":{"lei":"Redação dada pela Emenda Constitucional nº 24, de 1999","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§único: Os juízes classistas das Juntas de Conciliação e Julgamento serão nomeados pelo Presidente do Tribunal Regional do Trabalho, na forma da lei, permitida uma recondução.","redacaoDadaPor":{"lei":"Revogado pela Emenda Constitucional nº 24, de 1999","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
