      id: "cf:art-100",
      numero: "100",
      caput: "Até que entre em vigor a lei complementar de que trata o inciso II do § 1º do art. 40 da Constituição Federal , os Ministros do Supremo Tribunal Federal, dos Tribunais Superiores e do Tribunal de Contas da União aposentar-se-ão, compulsoriamente, aos 75 (setenta e cinco) anos de idade, nas condições do art. 52 da Constituição Federal .",
      paragrafos: [],
      incisos: [],
      referencias: ["cf:art-40","cf:art-52"],
      historico: [{"versao":1,"texto":"Até que entre em vigor a lei complementar de que trata o inciso II do § 1º do art. 40 da Constituição Federal , os Ministros do Supremo Tribunal Federal, dos Tribunais Superiores e do Tribunal de Contas da União aposentar-se-ão, compulsoriamente, aos 75 (setenta e cinco) anos de idade, nas condições do art. 52 da Constituição Federal .","redacaoDadaPor":{"lei":"Incluído pela Emenda Constitucional nº 88, de 2015","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
