    {
      tipo: "artigo" as const,
      id: "cf:art-135",
      numero: "135",
      caput: "Lei complementar disciplinará a forma de utilização dos créditos, inclusive presumidos, do imposto de que trata o art. 153, IV, e das contribuições de que tratam o art. 195, I, \"b\", e IV, e da contribuição para o Programa de Integração Social a que se refere o art. 239, todos da Constituição Federal, não apropriados ou não utilizados até a extinção, mantendo-se, apenas para os créditos que cumpram os requisitos estabelecidos na legislação vigente na data da extinção de tais tributos, a permissão para compensação com outros tributos federais, inclusive com a contribuição prevista no inciso V do caput do art. 195 da Constituição Federal, ou ressarcimento em dinheiro.",
      paragrafos: [],
      incisos: [],
      referencias: ["cf:art-153","cf:art-195","cf:art-239","cf:art-195"],
      historico: [{"versao":1,"texto":"Lei complementar disciplinará a forma de utilização dos créditos, inclusive presumidos, do imposto de que trata o art. 153, IV, e das contribuições de que tratam o art. 195, I, \"b\", e IV, e da contribuição para o Programa de Integração Social a que se refere o art. 239, todos da Constituição Federal, não apropriados ou não utilizados até a extinção, mantendo-se, apenas para os créditos que cumpram os requisitos estabelecidos na legislação vigente na data da extinção de tais tributos, a permissão para compensação com outros tributos federais, inclusive com a contribuição prevista no inciso V do caput do art. 195 da Constituição Federal, ou ressarcimento em dinheiro.","redacaoDadaPor":{"lei":"Incluído pela Emenda Constitucional nº 132, de 2023","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
